-- Commit 1: 2026 投保薪資分級表全量 (勞保 11 級 / 健保 58 級)
-- 來源: 勞動部勞動保2字第1140091863號令 / 衛部保字第1140153424號令
-- 費率: 勞保普通事故11.5% 就保1% 員工20% 雇主70%; 健保5.17% 員工30% 雇主60% 平均眷口0.56
-- 已於 prod Supabase SQL Editor 執行,本檔為歷史紀錄
-- ============================================================
BEGIN;

SELECT 'labor_before' AS tag, count(*) FROM labor_insurance_brackets;
SELECT 'health_before' AS tag, count(*) FROM health_insurance_brackets;

DELETE FROM labor_insurance_brackets;
DELETE FROM health_insurance_brackets;



SELECT 'labor_after' AS tag, count(*) AS n, min(insured_salary) AS lo, max(insured_salary) AS hi FROM labor_insurance_brackets;
SELECT 'health_after' AS tag, count(*) AS n, min(insured_salary) AS lo, max(insured_salary) AS hi FROM health_insurance_brackets;
SELECT bracket_level,insured_salary,employee_premium,company_premium FROM labor_insurance_brackets WHERE insured_salary=45800;
SELECT bracket_level,insured_salary,employee_premium,company_premium,per_dependent FROM health_insurance_brackets WHERE insured_salary IN (29500,45800);

COMMIT;
